2814	\begin{lemma}[The pulled-back sheaf is quasi-coherent on each preimage cover member]
2815	  \label{lem:isQuasicoherent_over_preimage}
2816	  \lean{AlgebraicGeometry.Scheme.Modules.isQuasicoherent_over_preimage}
2817	  \uses{def:over_restrict_presentation_inv, def:presentation_pullback_iota_preimage,
2818	    lem:presentation_isQuasicoherent_mathlib}
2819	  \textit{The abstract Grothendieck slice of the pullback over a preimage cover member is
2820	  quasi-coherent.}
2821	  With \(g : Y \to X\) an open immersion, \(M\) quasi-coherent with datum \(q\),
2822	  \(N := (\mathrm{pullback}\,g).\mathrm{obj}\,M\) and \(W_i := g^{-1}(q.X_i)\), the Grothendieck-slice
2823	  restriction \(N.\mathrm{over}\,W_i\) is quasi-coherent.
2824	\end{lemma}
2825	\begin{proof}
2826	  \uses{def:over_restrict_presentation_inv, def:presentation_pullback_iota_preimage,
2827	    lem:presentation_isQuasicoherent_mathlib}
2828	  Feed the geometric presentation of \((W_i.\iota^{*})\,N\)
2829	  (\cref{def:presentation_pullback_iota_preimage}) into the geometric-to-slice back-transport
2830	  \cref{def:over_restrict_presentation_inv} at \(V = W_i\), producing a presentation of the slice
2831	  \(N.\mathrm{over}\,W_i\). A sheaf with a presentation is quasi-coherent
2832	  (\cref{lem:presentation_isQuasicoherent_mathlib}).
2833	\end{proof}
