2853	\begin{lemma}[Pullback of a quasi-coherent sheaf along an open immersion is quasi-coherent]
2854	  \label{lem:isQuasicoherent_pullback_of_isOpenImmersion}
2855	  \lean{AlgebraicGeometry.Scheme.Modules.isQuasicoherent_pullback_of_isOpenImmersion}
2856	  \uses{lem:isQuasicoherent_quasicoherentData_mathlib, lem:isQuasicoherent_over_preimage,
2857	    lem:coversTop_preimage, lem:isQuasicoherent_of_coversTop_mathlib}
2858	  \textit{The general statement of which \cref{lem:qcoh_pullback_fromSpec} is the
2859	  \(g = \mathrm{fromSpec}\) instance.}
2860	  Let \(g : Y \to X\) be an open immersion and \(M\) a quasi-coherent sheaf of modules on \(X\). Then
2861	  the pullback \((\mathrm{pullback}\,g).\mathrm{obj}\,M\) is quasi-coherent.
2862	\end{lemma}
2863	\begin{proof}
2864	  \uses{lem:isQuasicoherent_quasicoherentData_mathlib, lem:isQuasicoherent_over_preimage,
2865	    lem:coversTop_preimage, lem:isQuasicoherent_of_coversTop_mathlib}
2866	  Choose quasi-coherence data \(q\) for \(M\) (\cref{lem:isQuasicoherent_quasicoherentData_mathlib})
2867	  and set \(N := (\mathrm{pullback}\,g).\mathrm{obj}\,M\). The preimage family
2868	  \(\{W_i := g^{-1}(q.X_i)\}\) covers \(Y\) (\cref{lem:coversTop_preimage}), and on each member the
2869	  slice \(N.\mathrm{over}\,W_i\) is quasi-coherent (\cref{lem:isQuasicoherent_over_preimage}). By the
2870	  local-to-global criterion \(\mathrm{IsQuasicoherent.of\_coversTop}\)
2871	  (\cref{lem:isQuasicoherent_of_coversTop_mathlib}) applied to this cover, \(N\) is quasi-coherent.
2872	\end{proof}
