2874	\begin{lemma}[Quasi-coherence is preserved under pullback along $\mathrm{fromSpec}$]
2875	  \label{lem:qcoh_pullback_fromSpec}
2876	  \lean{AlgebraicGeometry.Scheme.Modules.isQuasicoherent_pullback_fromSpec}
2877	  \uses{lem:isQuasicoherent_pullback_of_isOpenImmersion}
2878	  Let \(\mathcal{M}\) be a quasi-coherent sheaf of modules on a scheme \(X\) and let \(U \subseteq X\) be
2879	  an affine open with canonical affine immersion \(\mathrm{fromSpec} : \Spec \Gamma(X, U) \to X\). Then
2880	  the pullback \((\mathrm{pullback}\,\mathrm{fromSpec}).\mathrm{obj}\,\mathcal{M}\) is quasi-coherent.
2881	\end{lemma}
2882	\begin{proof}
2883	  \uses{lem:isQuasicoherent_pullback_of_isOpenImmersion}
2884	  The affine immersion \(\mathrm{fromSpec} : \Spec \Gamma(X, U) \to X\) of an affine open is an open
2885	  immersion (\(\mathrm{IsAffineOpen.fromSpec}\) is \(\mathrm{IsOpenImmersion}\), named in prose). Hence
2886	  this is the \(g := \mathrm{fromSpec}\) instance of the general statement
2887	  \cref{lem:isQuasicoherent_pullback_of_isOpenImmersion}: the pullback of the quasi-coherent sheaf
2888	  \(\mathcal{M}\) along the open immersion \(\mathrm{fromSpec}\) is quasi-coherent.
2889	\end{proof}
